447→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
448→
449→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
450→            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
451→            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
452→            pContri_buf++;
453→            out_tensor_ch2--;
454→        }
455→    }
456→
457→    /* When out_tensor_ch is small, the tiling GEMM (vqmacc vectorizing across
458→     * out_tensor_ch) severely underutilizes vector width.  Switch to vd4dots
459→     * which vectorizes along the reduction dimension (col) instead — giving
460→     * up to 32x better vector utilization for small channel counts. */
461→    if (out_tensor_ch <= 64)
462→    {
463→        /* Reuse src1 area as the 2-column im2col buffer (tiling buffer is
464→         * much larger than what 2-column batching needs). */
465→        int8_t *two_column_buf = src1;
466→
467→        for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
468→        {
469→            int8_t *two_col_ptr = two_column_buf;
470→            int8_t *out = out_tensor;
471→
472→            for (long cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
473→            {
474→                const long ker_y_start = cur_out_y * stride_y - pad_y;
475→                const long ker_y_end = ker_y_start + ker_dim_y;
476→                for (long cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
477→                {
478→                    const long ker_x_start = cur_out_x * stride_x - pad_x;
479→                    const long ker_x_end = ker_x_start + ker_dim_x;
480→                    for (long cur_ker_y = ker_y_start; cur_ker_y < ker_y_end; cur_ker_y++)
481→                    {
482→                        for (long cur_ker_x = ker_x_start; cur_ker_x < ker_x_end; cur_ker_x++)
483→                        {
484→                            if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
485→                            {
486→                                nn_set_val_s8(two_col_ptr, -in_offset, in_tensor_ch);
487→                            }
488→                            else
489→                            {
490→                                nn_dup_s8(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, two_col_ptr, in_tensor_ch);
491→                            }
492→                            two_col_ptr += in_tensor_ch;
493→                        }
494→                    }
495→
496→                    /* Computation is filed for every 2 columns */
497→                    if (two_col_ptr == two_column_buf + 2 * col)
498→                    {
499→                        out = nn_mat_mult_kernel_s8_offset_v4(ker_weight,
500→                                                              two_column_buf,
501→                                                              out_tensor_ch,
502→                                                              out_shift,
503→                                                              out_scale,
504→                                                              in_offset,
505→                                                              out_offset,
506→                                                              act_min,
507→                                                              act_max,
508→                                                              col,
509→                                                              contri_buf,
510→                                                              out);
511→
512→                        /* counter reset */
513→                        two_col_ptr = two_column_buf;
514→                    }
515→                }
516→            }
517→
518→            /* left-over because odd number of output pixels */
519→            if (two_col_ptr != two_column_buf)
520→            {
521→                uint32_t vl;
522→                const int8_t *pWt = ker_weight;
523→                const int32_t *pOut_scale = out_scale;
524→                const int32_t *pOut_shift = out_shift;
525→                int32_t *pContri_buf2 = contri_buf;
526→
527→                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
528→                NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
529→
530→                for (long i = 0; i < out_tensor_ch; i++)
531→                {
532→                    uint32_t rhs_cols2 = col;
533→                    const int8_t *pIn = two_column_buf;
534→
535→                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
536→                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
537→
538→                    while (rhs_cols2 >= maxvl_per_loop)
539→                    {
540→                        NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
541→                        NDS_VEC_VLE8_V(NDS_VEC_V8, pIn);
542→                        NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
543→                        rhs_cols2 -= vl;
544→                        pIn += vl;
545→                        pWt += vl;
546→
547→                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
548→                        NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
549→                    }
550→
551→                    if (rhs_cols2 > 0)
552→                    {
553→                        long tmp_avl = rhs_cols2 + 3;
554→                        NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
555→                        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
556→
557→                        NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
558→                        NDS_VEC_VLE8_V(NDS_VEC_V8, pIn);
559→                        NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
560→                        pWt += vl;
561→
562→                        vl = (vl + 3) >> 2;
563→                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
564→                        NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
565→                    }
566→                    /* rhs_cols2 == 0: pWt already advanced past this channel in the loop above */
567→
568→                    NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
569→                    NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
570→
571→                    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
572→                    NDS_VEC_VLE32_V(NDS_VEC_V4, pContri_buf2);
573→                    NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
574→
575→                    NDS_VEC_VLE32_V(NDS_VEC_V2, pOut_shift);
576→                    NDS_VEC_VLE32_V(NDS_VEC_V3, pOut_scale);
577→                    NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);
578→
579→                    NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V3);
580→                    NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
581→                    NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
582→
583→                    NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
584→                    NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
585→                    NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
586→
587→                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
588→                    NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
589→                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
590→                    NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
591→                    NDS_VEC_VSE8_V(NDS_VEC_V4, out);
592→                    out += vl;
593→                    pOut_scale += vl;
594→                    pOut_shift += vl;
595→                    pContri_buf2 += vl;
596→                }
597→            }
598→
599→            in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
600→            out_tensor += (out_tensor_dim_x * out_tensor_dim_y * out_tensor_ch);
601→        }
602→    }
603→    else
604→    {
605→    //transpose the kernel_weight for matrix multiplication
606→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, out_tensor_ch, in_tensor_ch * ker_dim_x * ker_dim_y);
607→
608→    int8_t *out = out_tensor;
609→    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
610→    {
611→        int8_t *src1_buf = src1;
612→        int col_counter = 0;
613→
614→        /* This part implements the im256col function */
615→        for (long cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
616→        {
617→            for (long cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
618→            {
619→                for (long cur_ker_y = cur_out_y * stride_y - pad_y; cur_ker_y < cur_out_y * stride_y - pad_y + ker_dim_y; cur_ker_y++)
620→                {
621→                    for (long cur_ker_x = cur_out_x * stride_x - pad_x; cur_ker_x < cur_out_x * stride_x - pad_x + ker_dim_x; cur_ker_x++)
622→                    {
623→                        if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
624→                        {
625→                            nn_set_val_s8(src1_buf, -in_offset, in_tensor_ch);
626→                        }
627→                        else
628→                        {
629→                            nn_dup_s8(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, src1_buf, in_tensor_ch);
630→                        }
631→                        src1_buf += in_tensor_ch;
632→                    }
633→                }
634→                col_counter++;
635→
636→                /* Computation is filed for every 256 columns */
637→                if (col_counter == tiling_size)
638→                {
639→                    out = nn_mat_mul_kernel_tiling_asym_s8_s8_s8(src1,
640→                                                                 src2,
641→                                                                 dst_i32,
642→                                                                 out,
643→                                                                 out_scale,
644→                                                                 out_shift,
645→                                                                 col_counter,
646→                                                                 in_tensor_ch * ker_dim_x * ker_dim_y,
647→                                                                 out_tensor_ch,
648→                                                                 out_offset,
649→                                                                 act_min,
650→                                                                 act_max,
651→                                                                 contri_buf,
652→                                                                 tiling_size);
653→
654→                    /* counter reset */
655→                    col_counter = 0;
656→                    src1_buf = src1;
657→                }
658→            }
659→        }
660→
661→        /* check if there is left-over for compute */
662→        out = nn_mat_mul_kernel_tiling_asym_s8_s8_s8(src1,
663→                                                     src2,
664→                                                     dst_i32,
665→                                                     out,
666→                                                     out_scale,
667→                                                     out_shift,
668→                                                     col_counter,
669→                                                     in_tensor_ch * ker_dim_x * ker_dim_y,
670→                                                     out_tensor_ch,
671→                                                     out_offset,
672→                                                     act_min,
673→                                                     act_max,
674→                                                     contri_buf,
675→                                                     tiling_size);
676→        /* next in_tensor batch offset */
677→        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
678→    }
679→    }
