 22→#include "internal_nn_math.h"
 23→
 24→//// Convolution Functions
 25→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
 26→q7_t *nn_mat_mul_kernel_q7_bias_2sft_unroll4(const q7_t * src1,
 27→                                             const q7_t * src2,
 28→                                             const uint16_t out_tensor_ch,
 29→                                             const uint16_t col_src1,
 30→                                             const uint16_t pre_rshift,
 31→                                             const uint16_t out_scale,
 32→                                             const uint16_t post_rshift,
 33→                                             const q31_t * bias,
 34→                                             q7_t * out)
 35→{
 36→#if defined(ENA_NDS_V5_VEC_DOT_PROD) && (ENA_VEC_INTRINSIC)
 37→    unsigned long vl;
 38→    unsigned long rowCnt = out_tensor_ch >> 2;
 39→    q7_t *pOut2 = out + out_tensor_ch;
 40→    q7_t *pOut3 = out + out_tensor_ch * 2;
 41→    q7_t *pOut4 = out + out_tensor_ch * 3;
 42→
 43→    const q7_t *pA = src1;
 44→
 45→    vl = __riscv_vsetvl_e32m1(1);
 46→    vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //keep zero for redsum
 47→
 48→    while(rowCnt > 0)
 49→    {
 50→        // setup pointers for A
 51→        const q7_t *pA2 = pA + col_src1;
 52→        const q7_t *pA3 = pA + col_src1 * 2;
 53→        const q7_t *pA4 = pA + col_src1 * 3;
 54→        // setup pointers for B
 55→        const q7_t *pB = src2;
 56→        const q7_t *pB2 = pB + col_src1;
 57→        const q7_t *pB3 = pB + col_src1 * 2;
 58→        const q7_t *pB4 = pB + col_src1 * 3;
 59→
 60→        vl = __riscv_vsetvlmax_e32m8();
 61→
 62→        //init
 63→        //clear v8~v23 (keep multiplication results)
 64→        vint32m8_t vZeroAccumulator1 = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
 65→        vint32m8_t vZeroAccumulator2 = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
 66→
 67→        vint32m1_t vAccumulator1 = __riscv_vget_i32m1(vZeroAccumulator1, 0);
 68→        vint32m1_t vAccumulator2 = __riscv_vget_i32m1(vZeroAccumulator1, 1);
 69→        vint32m1_t vAccumulator3 = __riscv_vget_i32m1(vZeroAccumulator1, 2);
 70→        vint32m1_t vAccumulator4 = __riscv_vget_i32m1(vZeroAccumulator1, 3);
 71→        vint32m1_t vAccumulator5 = __riscv_vget_i32m1(vZeroAccumulator1, 4);
 72→        vint32m1_t vAccumulator6 = __riscv_vget_i32m1(vZeroAccumulator1, 5);
 73→        vint32m1_t vAccumulator7 = __riscv_vget_i32m1(vZeroAccumulator1, 6);
 74→        vint32m1_t vAccumulator8 = __riscv_vget_i32m1(vZeroAccumulator1, 7);
 75→
 76→        vint32m1_t vAccumulator9 = __riscv_vget_i32m1(vZeroAccumulator2, 0);
 77→        vint32m1_t vAccumulator10 = __riscv_vget_i32m1(vZeroAccumulator2, 1);
 78→        vint32m1_t vAccumulator11 = __riscv_vget_i32m1(vZeroAccumulator2, 2);
 79→        vint32m1_t vAccumulator12 = __riscv_vget_i32m1(vZeroAccumulator2, 3);
 80→        vint32m1_t vAccumulator13 = __riscv_vget_i32m1(vZeroAccumulator2, 4);
 81→        vint32m1_t vAccumulator14 = __riscv_vget_i32m1(vZeroAccumulator2, 5);
 82→        vint32m1_t vAccumulator15 = __riscv_vget_i32m1(vZeroAccumulator2, 6);
 83→        vint32m1_t vAccumulator16 = __riscv_vget_i32m1(vZeroAccumulator2, 7);
 84→
 85→        unsigned long colCnt = col_src1;
 86→        while(colCnt > 0)
 87→        {
 88→            vl = __riscv_vsetvl_e8m1(colCnt);
 89→            //load src1 and src2
 90→            vint8m1_t vpA_i8m1 = __riscv_vle8_v_i8m1(pA, vl);
 91→            vint8m1_t vpA2_i8m1 = __riscv_vle8_v_i8m1(pA2, vl);
 92→            vint8m1_t vpA3_i8m1 = __riscv_vle8_v_i8m1(pA3, vl);
 93→            vint8m1_t vpA4_i8m1 = __riscv_vle8_v_i8m1(pA4, vl);
 94→
 95→            vint8m1_t vpB_i8m1 = __riscv_vle8_v_i8m1(pB, vl);
 96→            vint8m1_t vpB2_i8m1 = __riscv_vle8_v_i8m1(pB2, vl);
 97→            vint8m1_t vpB3_i8m1 = __riscv_vle8_v_i8m1(pB3, vl);
 98→            vint8m1_t vpB4_i8m1 = __riscv_vle8_v_i8m1(pB4, vl);
 99→
100→
101→            //bump pointers and update loop counter
102→            colCnt -= vl;
103→            pA += vl;
104→            pA2 += vl;
105→            pA3 += vl;
106→            pA4 += vl;
107→            pB += vl;
108→            pB2 += vl;
109→            pB3 += vl;
110→            pB4 += vl;
111→
112→            //set the proper avl/SEW/LMUL values for vd4dot
113→            vl >>= 2;
114→            vl = __riscv_vsetvl_e32m1(vl);
115→
116→            //acc += src1 * src2
117→            vAccumulator1 = __riscv_vd4dots_vv_i32m1(vAccumulator1, vpA_i8m1, vpB_i8m1, vl);
118→            vAccumulator2 = __riscv_vd4dots_vv_i32m1(vAccumulator2, vpA2_i8m1, vpB_i8m1, vl);
119→            vAccumulator3 = __riscv_vd4dots_vv_i32m1(vAccumulator3, vpA3_i8m1, vpB_i8m1, vl);
120→            vAccumulator4 = __riscv_vd4dots_vv_i32m1(vAccumulator4, vpA4_i8m1, vpB_i8m1, vl);
121→
122→            vAccumulator5 = __riscv_vd4dots_vv_i32m1(vAccumulator5, vpA_i8m1, vpB2_i8m1, vl);
123→            vAccumulator6 = __riscv_vd4dots_vv_i32m1(vAccumulator6, vpA2_i8m1, vpB2_i8m1, vl);
124→            vAccumulator7 = __riscv_vd4dots_vv_i32m1(vAccumulator7, vpA3_i8m1, vpB2_i8m1, vl);
125→            vAccumulator8 = __riscv_vd4dots_vv_i32m1(vAccumulator8, vpA4_i8m1, vpB2_i8m1, vl);
126→
127→            vAccumulator9 = __riscv_vd4dots_vv_i32m1(vAccumulator9, vpA_i8m1, vpB3_i8m1, vl);
128→            vAccumulator10 = __riscv_vd4dots_vv_i32m1(vAccumulator10, vpA2_i8m1, vpB3_i8m1, vl);
129→            vAccumulator11 = __riscv_vd4dots_vv_i32m1(vAccumulator11, vpA3_i8m1, vpB3_i8m1, vl);
130→            vAccumulator12 = __riscv_vd4dots_vv_i32m1(vAccumulator12, vpA4_i8m1, vpB3_i8m1, vl);
131→
132→            vAccumulator13 = __riscv_vd4dots_vv_i32m1(vAccumulator13, vpA_i8m1, vpB4_i8m1, vl);
133→            vAccumulator14 = __riscv_vd4dots_vv_i32m1(vAccumulator14, vpA2_i8m1, vpB4_i8m1, vl);
134→            vAccumulator15 = __riscv_vd4dots_vv_i32m1(vAccumulator15, vpA3_i8m1, vpB4_i8m1, vl);
135→            vAccumulator16 = __riscv_vd4dots_vv_i32m1(vAccumulator16, vpA4_i8m1, vpB4_i8m1, vl);
136→        }
137→        pA = pA4;
138→
139→        vl = __riscv_vsetvl_e32m1(col_src1);;    //note the avl here
140→        vint32m1_t vSum1 = __riscv_vredsum(vAccumulator1, vZero, vl);
141→        vint32m1_t vSum2 = __riscv_vredsum(vAccumulator2, vZero, vl);
142→        vint32m1_t vSum3 = __riscv_vredsum(vAccumulator3, vZero, vl);
143→        vint32m1_t vSum4 = __riscv_vredsum(vAccumulator4, vZero, vl);
144→
145→        vint32m1_t vSum5 = __riscv_vredsum(vAccumulator5, vZero, vl);
146→        vint32m1_t vSum6 = __riscv_vredsum(vAccumulator6, vZero, vl);
147→        vint32m1_t vSum7 = __riscv_vredsum(vAccumulator7, vZero, vl);
