341→        vint16mf2_t vSum2_i16mf2 = __riscv_vnsra(vSum2, post_rshift, vl);
342→        vint16mf2_t vSum4_i16mf2 = __riscv_vnsra(vSum4, post_rshift, vl);
343→        vint16mf2_t vSum6_i16mf2 = __riscv_vnsra(vSum6, post_rshift, vl);
344→        vl = __riscv_vsetvl_e8mf4(2);     //2: 2 acc
345→        vint8mf4_t vSum0_i8mf4 = __riscv_vnclip(vSum0_i16mf2, 0, __RISCV_VXRM_RNU, vl);
346→        vint8mf4_t vSum2_i8mf4 = __riscv_vnclip(vSum2_i16mf2, 0, __RISCV_VXRM_RNU, vl);
347→        vint8mf4_t vSum4_i8mf4 = __riscv_vnclip(vSum4_i16mf2, 0, __RISCV_VXRM_RNU, vl);
348→        vint8mf4_t vSum6_i8mf4 = __riscv_vnclip(vSum6_i16mf2, 0, __RISCV_VXRM_RNU, vl);
349→
350→        //store the results
351→        __riscv_vse8(out, vSum0_i8mf4, vl);
352→        __riscv_vse8(pOut2, vSum2_i8mf4, vl);
353→        __riscv_vse8(pOut3, vSum4_i8mf4, vl);
354→        __riscv_vse8(pOut4, vSum6_i8mf4, vl);
355→        out += vl;
356→        pOut2 += vl;
357→        pOut3 += vl;
358→        pOut4 += vl;
359→    }
360→
361→    out += out_tensor_ch * 3;
362→
363→    return out;
364→#elif defined(ENA_NDS_V5_VEC_DOT_PROD)
